const raw = $input.item.json.body || $input.item.json;

return [{
  json: {
    claim_id: raw.claim_id || ('CLM-' + Date.now()),
    policy_number: raw.policy_number || 'UNKNOWN',
    claimant_name: raw.claimant_name || 'Unknown Claimant',
    claimant_email: raw.claimant_email || '',
    date_of_loss: raw.date_of_loss || new Date().toISOString().split('T')[0],
    claim_type: raw.claim_type || 'other',
    description: raw.description || 'No description provided.',
    estimated_loss: raw.estimated_loss || '$0',
    location: raw.location || 'Unknown',
    policy_type: raw.policy_type || 'other',
    received_at: new Date().toISOString()
  }
}];

const claim = $('Normalize Claim Input').item.json;

const prompt = `You are an expert insurance claims analyst. Analyze the following claim submission and return a structured JSON response.

CLAIM SUBMISSION:
---
Claim ID: ${claim.claim_id}
Policy Number: ${claim.policy_number}
Claimant: ${claim.claimant_name}
Date of Loss: ${claim.date_of_loss}
Claim Type: ${claim.claim_type}
Description: ${claim.description}
Estimated Loss: ${claim.estimated_loss}
Location: ${claim.location}
---

Return ONLY valid JSON with this exact structure:
{
  "priority": "CRITICAL" | "HIGH" | "STANDARD" | "LOW",
  "claim_category": "property_damage" | "liability" | "auto" | "workers_comp" | "commercial" | "other",
  "extracted_fields": {
    "primary_cause": "string — one line root cause",
    "affected_parties": "string — who is impacted",
    "estimated_severity": "string — dollar range or severity descriptor",
    "coverage_flags": ["array of coverage areas that likely apply"],
    "red_flags": ["array of fraud indicators or unusual elements, empty if none"],
    "missing_info": ["array of critical missing fields needed to process"]
  },
  "recommended_specialist": "property_adjuster" | "liability_specialist" | "auto_adjuster" | "workers_comp_specialist" | "fraud_investigator" | "senior_adjuster",
  "sla_hours": 2 | 4 | 8 | 24 | 48,
  "confidence": 0.0–1.0,
  "reasoning": "2–3 sentence explanation of priority decision and key risk factors",
  "claimant_message": "1–2 sentence professional acknowledgment message for the claimant — empathetic, clear, no legal admissions"
}

Priority rules:
- CRITICAL: Estimated loss >$500K, injury claims, active liability exposure, fraud flags
- HIGH: Estimated loss $100K–$500K, commercial property, multiple parties
- STANDARD: Residential property <$100K, single claimant, clear documentation
- LOW: Minor claims <$10K, straightforward, complete documentation`;

return [{ json: { prompt } }];

const response = $('Claude: Extract & Triage').item.json;
const content = response.choices?.[0]?.message?.content || '';

let parsed;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch(e) {
  parsed = {
    priority: 'STANDARD',
    claim_category: 'other',
    extracted_fields: {
      primary_cause: 'Parse error — manual review required',
      affected_parties: 'Unknown',
      estimated_severity: 'Unknown',
      coverage_flags: [],
      red_flags: [],
      missing_info: ['AI parse failed — full manual review needed']
    },
    recommended_specialist: 'senior_adjuster',
    sla_hours: 8,
    confidence: 0.0,
    reasoning: 'AI extraction failed. Routing to senior adjuster for manual triage.',
    claimant_message: 'We have received your claim and a specialist will be in touch within 24 hours.'
  };
}

// Merge with original claim data
const claim = $('Normalize Claim Input').item.json;

return [{
  json: {
    ...claim,
    ...parsed,
    claim_id: claim.claim_id,
    processing_timestamp: new Date().toISOString()
  }
}];

