const d = $('Assign Specialist').item.json;
const ef = d.extracted_fields || {};
const flags = Array.isArray(ef.red_flags) ? ef.red_flags.join(', ') : 'None';
return [{ json: {
  'Date': new Date().toISOString().split('T')[0],
  'Claim ID': d.claim_id || '',
  'Claimant': d.claimant_name || '',
  'Claim Type': d.claim_category || '',
  'Priority': d.priority || '',
  'Est. Loss': d.estimated_loss || '',
  'SLA Hours': String(d.sla_hours || ''),
  'Assigned To': d.assigned_specialist_name || '',
  'Queue': d.assigned_queue || '',
  'Red Flags': flags || 'None',
  'Confidence': String(d.confidence || ''),
  'Reasoning': (d.reasoning || '').substring(0, 250),
  'Processed At': d.processing_timestamp || new Date().toISOString()
}}];

